import{_ as t,o as r,c as n,ag as i}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Projekte","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/projects.md","filePath":"de/features/projects.md"}'),a={name:"de/features/projects.md"};function s(o,e,l,u,d,h){return r(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="projekte" tabindex="-1">Projekte <a class="header-anchor" href="#projekte" aria-label="Permalink to &quot;Projekte&quot;">​</a></h1><p>Organisieren Sie Ihre Arbeit in Projekten, um Zeit, Umsatz und Rentabilität pro Auftrag zu verfolgen.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Projekte helfen Ihnen, Rechnungen, Ausgaben und Zeiteinträge zusammenzufassen. Dies gibt Ihnen ein klares Bild davon, wie rentabel jedes Projekt oder jeder Kundenauftrag ist.</p><h2 id="projekt-erstellen" tabindex="-1">Projekt erstellen <a class="header-anchor" href="#projekt-erstellen" aria-label="Permalink to &quot;Projekt erstellen&quot;">​</a></h2><ol><li>Gehen Sie zu <strong>Projekte &gt; Neues Projekt</strong></li><li>Füllen Sie aus: <ul><li><strong>Name</strong> — Ein aussagekräftiger Projektname</li><li><strong>Kunde</strong> — Der Kunde, für den dieses Projekt ist</li><li><strong>Beschreibung</strong> — Was das Projekt beinhaltet</li><li><strong>Budget</strong> — Optionaler Budgetbetrag</li><li><strong>Status</strong> — Aktiv, Pausiert oder Abgeschlossen</li></ul></li><li>Klicken Sie auf <strong>Speichern</strong></li></ol><h2 id="projektstatus" tabindex="-1">Projektstatus <a class="header-anchor" href="#projektstatus" aria-label="Permalink to &quot;Projektstatus&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>Aktiv</strong></td><td>Wird derzeit bearbeitet</td></tr><tr><td><strong>Pausiert</strong></td><td>Vorübergehend unterbrochen</td></tr><tr><td><strong>Abgeschlossen</strong></td><td>Fertig — keine weitere Arbeit erwartet</td></tr><tr><td><strong>Archiviert</strong></td><td>Zur Referenz gespeichert</td></tr></tbody></table><h2 id="projektdetailseite" tabindex="-1">Projektdetailseite <a class="header-anchor" href="#projektdetailseite" aria-label="Permalink to &quot;Projektdetailseite&quot;">​</a></h2><p>Die Projektdetailseite zeigt:</p><ul><li><strong>Übersicht</strong> — Name, Kunde, Status, Budget</li><li><strong>Verknüpfte Rechnungen</strong> — Alle Rechnungen zu diesem Projekt</li><li><strong>Verknüpfte Ausgaben</strong> — Diesem Projekt zugeordnete Kosten</li><li><strong>Zeiteinträge</strong> — Für dieses Projekt erfasste Stunden</li><li><strong>Rentabilität</strong> — Aufschlüsselung Umsatz vs. Kosten</li></ul><h2 id="elemente-mit-projekten-verknupfen" tabindex="-1">Elemente mit Projekten verknüpfen <a class="header-anchor" href="#elemente-mit-projekten-verknupfen" aria-label="Permalink to &quot;Elemente mit Projekten verknüpfen&quot;">​</a></h2><p>Beim Erstellen von Rechnungen, Ausgaben oder Zeiteinträgen wählen Sie das Projekt aus der Dropdown-Liste, um sie zu verknüpfen. Dies aktualisiert automatisch die Finanzdaten des Projekts.</p><ul><li><strong>Rechnungen</strong> — Umsatz pro Projekt verfolgen</li><li><strong>Ausgaben</strong> — Kosten pro Projekt verfolgen</li><li><strong>Zeiteinträge</strong> — Stunden pro Projekt verfolgen</li></ul><h2 id="budgetverfolgung" tabindex="-1">Budgetverfolgung <a class="header-anchor" href="#budgetverfolgung" aria-label="Permalink to &quot;Budgetverfolgung&quot;">​</a></h2><p>Wenn Sie ein Budget festlegen:</p><ul><li>Sehen Sie, wie viel des Budgets verbraucht wurde</li><li>Verfolgen Sie das verbleibende Budget</li><li>Vergleichen Sie tatsächliche Kosten mit dem Budget</li><li>Erhalten Sie Warnungen, wenn Sie sich den Budgetgrenzen nähern</li></ul><h2 id="massenaktionen" tabindex="-1">Massenaktionen <a class="header-anchor" href="#massenaktionen" aria-label="Permalink to &quot;Massenaktionen&quot;">​</a></h2><ul><li><strong>Status ändern</strong> — Mehrere Projekte gleichzeitig aktualisieren</li><li><strong>Archivieren</strong> — Abgeschlossene Projekte ins Archiv verschieben</li><li><strong>Wiederherstellen</strong> — Archivierte Projekte zurückholen</li></ul><h2 id="berichte" tabindex="-1">Berichte <a class="header-anchor" href="#berichte" aria-label="Permalink to &quot;Berichte&quot;">​</a></h2><p>Sehen Sie die Projektleistung in den <a href="/de/features/reports">Kundenberichten</a>:</p><ul><li>Umsatz pro Projekt</li><li>Zeitaufwand pro Projekt</li><li>Gewinnmargen</li><li>Vergleich über Projekte hinweg</li></ul><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Verwenden Sie Projekte auch für kleine Aufträge — die Einblicke sind wertvoll</li><li>Verknüpfen Sie sowohl Rechnungen als auch Ausgaben, um genaue Gewinnmargen zu erhalten</li><li>Archivieren Sie abgeschlossene Projekte, um Ihre aktive Liste übersichtlich zu halten</li><li>Schauen Sie sich das projektbasierte Dashboard-Profil für eine projektfokussierte Ansicht an</li></ul>',24)])])}const k=t(a,[["render",s]]);export{c as __pageData,k as default};
